  data: Record<string, unknown>,
  options: { preserveWhitespace?: boolean } = {},
): string {
  const candidate =
    data.text ?? data.message ?? data.delta ?? data.chunk ?? data.content;

  if (typeof candidate !== 'string') {
    return '';
